package com.chaobo.scm.supplier.domain.profile;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.domain.shared.*;import java.time.*;import java.util.*;
public final class SupplierAdmissionAggregate{private final long id;private final String no,code,name,taxNo,type,contactName,contactMobile,settlementJson;private SupplierAdmissionStatus status;private String rejectReason;private int version;private final List<DomainEvent> events=new ArrayList<>();private SupplierAdmissionAggregate(long id,String no,String code,String name,String taxNo,String type,String contactName,String contactMobile,String settlementJson,SupplierAdmissionStatus status,String rejectReason,int version){this.id=id;this.no=no;this.code=code;this.name=name;this.taxNo=taxNo;this.type=type;this.contactName=contactName;this.contactMobile=contactMobile;this.settlementJson=settlementJson;this.status=status;this.rejectReason=rejectReason;this.version=version;valid();}public static SupplierAdmissionAggregate create(String code,String name,String tax,String type,String contact,String mobile,String settlement,long op,IdentifierGenerator ids){var a=new SupplierAdmissionAggregate(ids.nextId(),ids.nextBusinessNo("SA"),code,name,tax,type,contact,mobile,settlement,SupplierAdmissionStatus.POTENTIAL,null,0);a.raise(ids,"SupplierPotentialCreated","潜在供应商已创建",op);return a;}public static SupplierAdmissionAggregate rehydrate(long id,String no,String code,String name,String tax,String type,String contact,String mobile,String settlement,int status,String reject,int version){return new SupplierAdmissionAggregate(id,no,code,name,tax,type,contact,mobile,settlement,SupplierAdmissionStatus.fromCode(status),reject,version);}public void submit(long op,IdentifierGenerator ids){require(SupplierAdmissionStatus.POTENTIAL,SupplierAdmissionStatus.REJECTED);status=SupplierAdmissionStatus.PENDING;rejectReason=null;version++;raise(ids,"SupplierAdmissionSubmitted","供应商准入已提交",op);}public void approve(long op,IdentifierGenerator ids){require(SupplierAdmissionStatus.PENDING);status=SupplierAdmissionStatus.APPROVED;version++;raise(ids,"SupplierAdmissionApproved","供应商准入已通过",op);}public void reject(String reason,long op,IdentifierGenerator ids){require(SupplierAdmissionStatus.PENDING);if(reason==null||reason.isBlank())throw rule("驳回原因不能为空");status=SupplierAdmissionStatus.REJECTED;rejectReason=reason.trim();version++;raise(ids,"SupplierAdmissionRejected","供应商准入已驳回",op);}public void withdraw(String reason,long op,IdentifierGenerator ids){require(SupplierAdmissionStatus.POTENTIAL,SupplierAdmissionStatus.PENDING);status=SupplierAdmissionStatus.WITHDRAWN;rejectReason=reason;version++;raise(ids,"SupplierAdmissionWithdrawn","供应商准入已撤回",op);}private void valid(){if(code==null||code.isBlank()||name==null||name.isBlank()||taxNo==null||taxNo.isBlank()||type==null||type.isBlank()||contactName==null||contactName.isBlank()||contactMobile==null||contactMobile.isBlank()||settlementJson==null||settlementJson.isBlank())throw rule("供应商准入资料不完整");}private void require(SupplierAdmissionStatus...statuses){for(var s:statuses)if(status==s)return;throw new BusinessException(ErrorCode.STATE_CONFLICT,"准入状态不允许当前操作");}private void raise(IdentifierGenerator ids,String type,String name,long op){long event=ids.nextId();events.add(new DomainEvent(event,"SUP-"+event,type,name,"SUPPLIER_ADMISSION",id,no,version,op,OffsetDateTime.now(),Map.of("admissionId",id,"supplierCode",code,"supplierName",this.name,"taxNo",taxNo,"supplierType",this.type)));}private static BusinessException rule(String m){return new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,m);}public List<DomainEvent> pullEvents(){var result=List.copyOf(events);events.clear();return result;}public long id(){return id;}public String no(){return no;}public String code(){return code;}public String name(){return name;}public String taxNo(){return taxNo;}public String type(){return type;}public String contactName(){return contactName;}public String contactMobile(){return contactMobile;}public String settlementJson(){return settlementJson;}public SupplierAdmissionStatus status(){return status;}public String rejectReason(){return rejectReason;}public int version(){return version;}}
